const d=$json;let type='',msg='',sev='info';
if(d.rsi_sig==='oversold'&&d.macd_sig==='bullish'){type='strong_buy';msg=`${d.company_name} (${d.ticker}): RSI oversold + MACD bullish`;sev='warning';}
else if(d.rsi_sig==='oversold'){type='buy_signal';msg=`${d.company_name} (${d.ticker}): RSI oversold at ${d.rsi?.toFixed(1)}`;}
else if(d.rsi_sig==='overbought'){type='sell_signal';msg=`${d.company_name} (${d.ticker}): RSI overbought at ${d.rsi?.toFixed(1)}`;sev='warning';}
return [{json:{ticker:d.ticker,signal_type:type,message:msg,severity:sev}}];
